import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Портування до знімків 26.1","description":"Посібник про те, як портувати до знімків 26.1, майбутньої версії Minecraft.","frontmatter":{"title":"Портування до знімків 26.1","description":"Посібник про те, як портувати до знімків 26.1, майбутньої версії Minecraft.","authors":["cassiancc"],"resources":{"./26.1/fabric-api":"Посібник з портування Fabric API 26.1","https://minecraft.wiki/w/Java_Edition_26.1":"Java Edition 26.1 — Вікі Minecraft","https://github.com/ChampionAsh5357/neoforged-github/blob/update/26.1/primers/26.1/index.md":"Праймери міграції 1.21.11 -> 26.1 від ChampionAsh5357"},"files":[]},"headers":[],"relativePath":"uk_ua/26.1/develop/porting/index.md","filePath":"translated/uk_ua/26.1/develop/porting/index.md","lastUpdated":1774518827000}`);var a={name:`uk_ua/26.1/develop/porting/index.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Портування до знімків 26.1 <a class="header-anchor" href="#h1" aria-label="Permalink to “Портування до знімків 26.1”">​</a></h1><p>Майбутня версія Minecraft 26.1 не обфускована, як і її знімки. Зважаючи на це, вам потрібно буде внести більше змін у свої сценарії збірки, ніж зазвичай, щоб перейти на нього.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>У цих документах обговорюється міграція з <strong>1.21.11</strong> на знімки майбутньої <strong>26.1</strong>. Якщо ви шукаєте іншу міграцію, перейдіть до цільової версії за допомогою спадного меню у верхньому правому куті.</p></div><h2 id="prerequisites" tabindex="-1">Передумови <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Передумови”">​</a></h2><p>Якщо ваш мод досі використовує мапінги Yarn Fabric, вам спочатку потрібно буде <a href="./../../../develop/porting/mappings/">перенести свій мод до офіційних мапінгів Mojang</a> перед портуванням на 26.1.</p><p>Якщо ви використовуєте IntelliJ IDEA, вам також потрібно оновити його до <code>2025.3</code> або новішої версії для повної підтримки Java 25.</p><h2 id="build-script" tabindex="-1">Оновлення скриптів збірки <a class="header-anchor" href="#build-script" aria-label="Permalink to “Оновлення скриптів збірки”">​</a></h2><p>Почніть з оновлення <code>gradle/wrapper/gradle-wrapper.properties</code>, <code>gradle.properties</code> і <code>build.gradle</code> вашого мода до останніх версій.</p><ol><li>Оновіть Gradle до останньої версії, виконавши таку команду: <code>./gradlew wrapper --gradle-version latest</code></li><li>Оновіть Minecraft, Завантажувач Fabric, Fabric Loom і Fabric API у <code>gradle.properties</code> (рекомендовано) або <code>build.gradle</code>. Знайдіть рекомендовані версії компонентів Fabric на <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">сайті розробки Fabric</a>. <ul><li>Зауважте, що оскільки знімки 26.1 не є стабільною версією Minecraft, вам потрібно буде вибрати цю версію вручну зі спадного списку.</li></ul></li><li>У верхній частині <code>build.gradle</code> змініть версію Loom, яку ви використовуєте, з <code>id &quot;fabric-loom&quot;</code> на <code>id &quot;net.fabricmc.fabric-loom&quot;</code>. Якщо ви вказали Loom у <code>settings.gradle</code>, змініть його також там.</li><li>Видаліть рядок <code>mappings</code> із розділу залежностей <code>build.gradle</code>.</li><li>Замініть будь-які випадки <code>modImplementation</code> або <code>modCompileOnly</code> на <code>implementation</code> і <code>compileOnly</code>.</li><li>Видаліть або замініть будь-які моди, створені для версій до 26.1, на версії, сумісні з цим оновленням. <ul><li>Жодні наявні моди для 1.21.11 або старіших версій Minecraft не працюватимуть 26.1, навіть як залежність лише від компіляції.</li></ul></li><li>Замініть усі згадки <code>remapJar</code> на <code>jar</code>.</li><li>Оновіть Gradle за допомогою кнопки оновлення у верхньому правому куті IntelliJ IDEA. Якщо цю кнопку не видно, ви можете примусово очистити кеші, запустивши <code>./gradlew --refresh-dependencies</code>.</li></ol><h2 id="porting-guides" tabindex="-1">Оновлення коду <a class="header-anchor" href="#porting-guides" aria-label="Permalink to “Оновлення коду”">​</a></h2><p>Після оновлення сценарію збірки до версії 26.1 ви можете переглянути свій мод і оновити будь-який змінений код, щоб зробити його сумісним зі знімком.</p><div class="warning custom-block"><p class="custom-block-title">ВАЖЛИВО</p><p>Оскільки Minecraft 26.1 все ще знаходиться на стадії знімків, документація про конкретні зміни все ще відсутня. Успіхів, далі ви самі!</p></div><ul><li><a href="./fabric-api">Посібник з портування Fabric API 26.1</a> містить список перейменувань, зроблених у Fabric API у знімках 26.1, щоб відповідати іменам Mojang.</li><li><a href="https://minecraft.wiki/w/Java_Edition_26.1" target="_blank" rel="noreferrer"><em>Java Edition 26.1</em> на Вікі Minecraft</a> — це неофіційний короткий виклад вмісту оновлення.</li><li><a href="https://github.com/neoforged/.github/blob/main/primers/26.1/index.md" target="_blank" rel="noreferrer">Праймер NeoForge міграції мода Minecraft 1.21.11 -&gt; 26.1</a> охоплює перехід з 1.21.11 на 26.1, зосереджуючись лише на змінах коду. <ul><li>Будь ласка, зверніть увагу, що стаття, на яку посилається, є стороннім матеріалом, який не підтримується Fabric. Захищено авторським правом @ChampionAsh5357 і ліцензовано за <a href="https://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">Creative Commons Attribution 4.0 International</a>.</li></ul></li></ul>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};